// Fecha actual en hora de Santiago (UTC-3 verano / UTC-4 invierno)
// toLocaleDateString con 'en-CA' devuelve YYYY-MM-DD, el formato que usa Relbase.
const hoy = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Santiago' });

return [{ json: { hoy } }];

// Fetch paginado de todas las ventas del día desde Relbase.
// Relbase pagina de a 12 registros (verificar si es 12 o diferente en producción).
// Rate limit Relbase: 7 req/seg → sleep 150ms entre páginas.

const hoy = $input.first().json.hoy;
const BASE  = process.env.RELBASE_BASE_URL;
const AUTH  = process.env.RELBASE_TOKEN_USUARIO;
const COMP  = process.env.RELBASE_TOKEN_EMPRESA;
const PAGE_SIZE = 12; // ajustar si Relbase usa un tamaño distinto

if (!BASE || !AUTH || !COMP) {
  throw new Error('Variables RELBASE_BASE_URL, RELBASE_TOKEN_USUARIO o RELBASE_TOKEN_EMPRESA no definidas');
}

const todos = [];
let pagina = 1;

while (true) {
  const url = `${BASE}/api/v1/dtes?start_date=${hoy}&end_date=${hoy}&page=${pagina}`;
  const res = await fetch(url, {
    headers: {
      'Authorization': AUTH,
      'Company': COMP,
    }
  });

  if (!res.ok) {
    throw new Error(`Relbase error ${res.status} en /api/v1/dtes?page=${pagina}: ${await res.text()}`);
  }

  const data = await res.json();
  // Relbase puede devolver array directo o { data: [...] } según versión
  const lista = Array.isArray(data) ? data : (data.data || data.dtes || []);
  todos.push(...lista);

  if (lista.length < PAGE_SIZE) break; // última página
  pagina++;
  await new Promise(r => setTimeout(r, 150));
}

return todos.map(dte => ({ json: dte }));

// Mapea cada DTE al schema real de Supabase.
// Schema ventas (verificado contra PostgREST / transformer.py):
//   relbase_id, tipo_documento, folio, estado_sii, fecha_emision,
//   neto, iva, total, vendedor, canal, forma_pago
// cliente_id y bodega_id (FKs uuid) se resuelven en el loader Python;
// en este sync se omiten deliberadamente para no bloquear el upsert diario.

return $input.all().map(item => {
  const d = item.json;
  return {
    json: {
      relbase_id:    d.id,
      tipo_documento: d.type_document || d.tipo_documento,
      folio:         d.folio          || null,
      estado_sii:    d.sii_status_name || d.estado_sii || null,
      fecha_emision: (d.start_date || d.fecha_emision || '').slice(0, 10) || null,
      neto:          d.amount_neto   || d.neto  || 0,
      iva:           d.amount_iva    || d.iva   || 0,
      total:         d.amount_total  || d.total || 0,
      vendedor:      d.vendedor_nombre || d.vendedor || null,
      forma_pago:    d.payment_method_name || d.payment_method || d.forma_pago || null,
      canal:         'presencial',
    }
  };
});

// Recibe las ventas con UUID ya asignado por Supabase (return=representation).
// Por cada venta, llama a GET /api/v1/dtes/{relbase_id} para obtener las líneas.
// Mapea las líneas al schema de ventas_detalle.

const BASE = process.env.RELBASE_BASE_URL;
const AUTH = process.env.RELBASE_TOKEN_USUARIO;
const COMP = process.env.RELBASE_TOKEN_EMPRESA;

// $input puede venir como array de objetos o como un objeto con array
const ventasSupabase = $input.all().map(i => {
  // Supabase retorna array; n8n puede envolverlo en item.json o directo
  if (Array.isArray(i.json)) return i.json;
  return [i.json];
}).flat();

const todasLineas = [];

for (const venta of ventasSupabase) {
  const dteId   = venta.relbase_id;
  const ventaId = venta.id; // UUID de Supabase

  if (!dteId) continue;

  const url = `${BASE}/api/v1/dtes/${dteId}`;
  const res = await fetch(url, {
    headers: { 'Authorization': AUTH, 'Company': COMP }
  });

  if (!res.ok) {
    // No lanzar: continuar con el siguiente DTE y loguear
    console.error(`Detalle DTE ${dteId} error: ${res.status}`);
    continue;
  }

  const dte   = await res.json();
  // Relbase devuelve las líneas en distintos campos según versión
  const items = dte.items || dte.details || dte.lines || dte.detalles || [];

  for (let i = 0; i < items.length; i++) {
    const it = items[i];
    const cantidad = it.quantity ?? it.cantidad ?? 0;
    const precio   = it.price    ?? it.precio_unitario;
    const descuento = it.discount ?? it.descuento_pct ?? 0;
    const totalNeto = it.total ?? it.total_neto
      ?? (precio && cantidad ? parseFloat((precio * cantidad * (1 - descuento / 100)).toFixed(2)) : null);

    todasLineas.push({
      json: {
        dte_id_relbase:      dteId,
        venta_id:            ventaId,
        numero_linea:        i + 1,
        relbase_producto_id: it.product_id  || it.relbase_producto_id || null,
        nombre_producto:     it.name        || it.nombre_producto     || it.descripcion || null,
        sku:                 it.code        || it.sku                 || it.codigo      || null,
        cantidad,
        precio_unitario:     precio         ?? null,
        costo_unitario:      it.unit_cost   || it.costo_unitario      || null,
        descuento_pct:       descuento,
        afecto_iva:          it.is_tax_affected !== undefined ? it.is_tax_affected : true,
        total_neto:          totalNeto,
      }
    });
  }

  await new Promise(r => setTimeout(r, 150)); // rate limit Relbase
}

if (!todasLineas.length) {
  return [{ json: { _sin_detalle: true } }];
}

return todasLineas;

